} from "./actions.js";

export type TurnEvent = EngineLogEvent;

export type ActorEntity = Extract<EntityInstance, { readonly kind: "enemy" | "npc" }>;

export type ActionResolverActionKind =
  | "move"
  | "attack"
  | "use_item"
  | "pickup"
  | "talk"
  | "inspect";

export type ActionResolverAction = Extract<
  PlayerAction,
  { readonly kind: ActionResolverActionKind }
>;

export type ActionResolverSuccess = {
  readonly state: GameState;
  readonly events: readonly TurnEvent[];
};

export type ActionResolverIllegal = {
  readonly illegal: true;
  readonly reason: string;
};

export type ActionResolverResult =
  | ActionResolverSuccess
  | ActionResolverIllegal;

export type ActionResolver<
  Action extends ActionResolverAction = ActionResolverAction,
> = (state: GameState, action: Action) => ActionResolverResult;

export type TickHookName =
  | "damageOverTime"
  | "durations"
  | "hunger"
  | "regen";

export const TICK_HOOK_ORDER = [
  "damageOverTime",
  "durations",
  "hunger",
  "regen",
] as const satisfies readonly TickHookName[];

export type TurnHookResult =
  | GameState
  | {
      readonly state: GameState;
      readonly events?: readonly TurnEvent[];
    };

export type ActorTurnHook = (context: {
  readonly state: GameState;
  readonly actor: ActorEntity;
  readonly action: PlayerAction;
}) => TurnHookResult;

export type TickHook = (context: {
  readonly state: GameState;
  readonly hook: TickHookName;
  readonly action: PlayerAction;
}) => TurnHookResult;

export type TickHooks = {
  readonly [Hook in TickHookName]: TickHook;
};

export type TurnHooks = {
  readonly actorTurn?: ActorTurnHook;
  readonly ticks?: Partial<TickHooks>;
};

export type ResolvedTurnHooks = {
  readonly actorTurn: ActorTurnHook;
  readonly ticks: TickHooks;
};

export type StepOptions = {
  readonly hooks?: TurnHooks;
};

export type StepResult = {
  readonly state: GameState;
  readonly events: readonly TurnEvent[];
};

export type StartContent = {
  readonly config?: GameConfig;
};

const actionResolvers = new Map<ActionResolverActionKind, ActionResolver>();

export const registerActionResolver = <
  Kind extends ActionResolverActionKind,
>(
  actionType: Kind,
  resolver: ActionResolver<Extract<PlayerAction, { readonly kind: Kind }>>,
): (() => void) => {
  const previous = actionResolvers.get(actionType);
  const registeredResolver = resolver as ActionResolver;
  actionResolvers.set(actionType, registeredResolver);

import { bounds } from "../../config/index.js";
import {
  StatusApplicationSchema,
  type StatusApplication,
  type StatusId,
} from "../../schemas/vocab/index.js";
import type { Rng } from "../rng/index.js";
import type {
  EngineLogEventDataByType,
  EnemyEntityInstance,
  EntityId,
  GameState,
} from "../state/index.js";
import {
  MOVE_DIRECTIONS,
  type MoveDirection,
  type TickHook,
  type TickHooks,
  type TurnEvent,
} from "../turn/index.js";

export type StatusEntityId = EntityId | "player";

declare module "../state/types.js" {
  interface EngineLogEventDataByType {
    readonly status_applied: {
      readonly entityId: StatusEntityId;
      readonly status: StatusId;
      readonly duration: number;
    };
    readonly status_refreshed: {
      readonly entityId: StatusEntityId;
      readonly status: StatusId;
      readonly duration: number;
    };
    readonly status_expired: {
      readonly entityId: StatusEntityId;
      readonly status: StatusId;
    };
    readonly status_dropped_oldest: {
      readonly entityId: StatusEntityId;
      readonly status: StatusId;
    };
    readonly status_tick: {
      readonly entityId: StatusEntityId;
      readonly status: StatusId;
      readonly hpDelta: number;
    };
  }
}

type StatusLogEventType =
  | "status_applied"
  | "status_refreshed"
  | "status_expired"
  | "status_dropped_oldest"
  | "status_tick";

type StatusTickHookName = "damageOverTime" | "durations";

const MAX_CONCURRENT_STATUSES = bounds.statusVocabulary.maxConcurrentPerActor;

const HASTE_SLOW_PAIR: ReadonlySet<StatusId> = new Set(["haste", "slow"]);

const DOT_STATUSES: ReadonlySet<StatusId> = new Set(["poison", "burn", "regen"]);

export type ApplyStatusResult = {
  readonly state: GameState;
  readonly events: readonly TurnEvent[];
};

export const applyStatus = (
  state: GameState,
  entityId: StatusEntityId,
  status: StatusId,
  duration: number,
): ApplyStatusResult => {
  const parsed = StatusApplicationSchema.safeParse({ status, duration });
  if (!parsed.success) {
    return { state, events: [] };
  }

  const application = parsed.data;
  const events: TurnEvent[] = [];
  let statuses = statusesForEntity(state, entityId);

  if (HASTE_SLOW_PAIR.has(status)) {
    const opposite = status === "haste" ? "slow" : "haste";
    const hadOpposite = statuses.some((entry) => entry.status === opposite);
    if (hadOpposite) {
      statuses = statuses.filter((entry) => entry.status !== opposite);
    }
  }

  const existingIndex = statuses.findIndex(
    (entry) => entry.status === application.status,
  );

  if (existingIndex >= 0) {
    statuses = statuses.map((entry, index) =>
      index === existingIndex
        ? { status: application.status, duration: application.duration }
        : entry,
    );
    events.push(
      statusEvent(state, "status_refreshed", {
        entityId,
        status: application.status,
        duration: application.duration,
      }),
    );
  } else {
    if (statuses.length >= MAX_CONCURRENT_STATUSES) {
      const dropped = statuses[0];
      if (dropped !== undefined) {
        statuses = statuses.slice(1);
        events.push(
          statusEvent(state, "status_dropped_oldest", {
            entityId,
            status: dropped.status,
          }),
        );
      }
    }

    statuses = [...statuses, application];
    events.push(
      statusEvent(state, "status_applied", {
        entityId,
        status: application.status,
        duration: application.duration,
      }),
    );
  }

  return {
    state: withEntityStatuses(state, entityId, statuses),
    events,
  };
};

export const isStunned = (statuses: readonly StatusApplication[]): boolean =>
  statuses.some((entry) => entry.status === "stun" && entry.duration > 0);

export const slowActsThisTurn = (turn: number): boolean => turn % 2 === 0;

export const hasteExtraAction = (turn: number): boolean => turn % 2 === 1;

export const confusionRedirect = (
  rng: Rng,
  intendedDir: MoveDirection,
): MoveDirection => {
  void intendedDir;
  return rng.fork("status").pick(MOVE_DIRECTIONS.map((entry) => entry.direction));
};

export const blindFovRadius = (
  statuses: readonly StatusApplication[],
): number | null =>
  statuses.some((entry) => entry.status === "blind" && entry.duration > 0) ? 1 : null;

import { bounds, config } from "../../config/index.js";
import type { Effect, StatusApplication } from "../../schemas/vocab/index.js";
import {
  canSee,
  chebyshevDistance,
  getTile,
  inBounds,
  isTransparentTile,
  line,
  type TileGrid,
} from "../map/index.js";
import { createRng, type Rng } from "../rng/index.js";
import type {
  EngineLogEventDataByType,
  EnemyEntityInstance,
  EntityId,
  GameState,
  PlayerItemStack,
  Position,
  SerializableRecord,
} from "../state/index.js";
import {
  registerActionResolver,
  type ActionResolver,
  type ActionResolverResult,
  type AttackAction,
  type TurnEvent,
} from "../turn/index.js";

export type PlayerActorId = "player";
export type CombatActorId = PlayerActorId | EntityId;

export type CombatStats = {
  readonly attack: number;
  readonly defense: number;
};

export type CombatResolutionEventType = "attack_hit" | "attack_missed";

export type AttackMissReason =
  | "hit_roll"
  | "line_of_sight_blocked"
  | "no_target";

export type LootDropContext = {
  readonly state: GameState;
  readonly victim: EnemyEntityInstance;
  readonly killerId: CombatActorId;
};

export type LootDropResult =
  | GameState
  | {
      readonly state: GameState;
      readonly events?: readonly TurnEvent[];
    };

export type LootDropHook = (context: LootDropContext) => LootDropResult;

declare module "../state/types.js" {
  interface EngineLogEventDataByType {
    readonly attack_hit: {
      readonly actorId: CombatActorId;
      readonly defenderId: CombatActorId;
      readonly attackerAttack: number;
      readonly defenderDefense: number;
      readonly baseDamage: number;
      readonly damage: number;
      readonly hitRoll: number;
      readonly hitChancePercent: number;
      readonly varianceMultiplier: number;
      readonly defenderHpBefore: number;
      readonly defenderHpAfter: number;
    };
    readonly attack_missed: {
      readonly actorId: CombatActorId;
      readonly defenderId: CombatActorId | null;
      readonly attackerAttack: number | null;
      readonly defenderDefense: number | null;
      readonly hitRoll: number | null;
      readonly hitChancePercent: number;
      readonly reason: AttackMissReason;
    };
    readonly entity_died: {
      readonly entityId: CombatActorId;
      readonly kind: "enemy" | "player";
      readonly position: Position;
