    };
    readonly xp_gained: {
      readonly actorId: PlayerActorId;
      readonly sourceEntityId: EntityId;
      readonly amount: number;
      readonly totalXp: number;
    };
  }
}

const COMBAT_RNG_STREAM_ID = "combat";
const ROOT_RNG_STREAM_ID = "root";
const UINT32_SIZE = 0x1_0000_0000;
const HIT_ROLL_MIN = 1;
const HIT_ROLL_MAX = 100;

/*
 * GAME_DESIGN §6 pins these status magnitudes. Config currently stores the
 * status vocabulary bounds but not per-status stat magnitudes.
 */
const STATUS_SHIELD_DEFENSE_BONUS = 3;
const STATUS_WEAKEN_ATTACK_PENALTY = -2;

let lootDropHook: LootDropHook = ({ state }) => state;

type CombatActor =
  | {
      readonly id: PlayerActorId;
      readonly kind: "player";
      readonly position: Position;
      readonly hp: number;
      readonly statuses: readonly StatusApplication[];
    }
  | {
      readonly id: EntityId;
      readonly kind: "enemy";
      readonly entity: EnemyEntityInstance;
      readonly position: Position;
      readonly hp: number;
      readonly statuses: readonly StatusApplication[];
    };

type MutableRngContext = {
  readonly rng: Rng;
  readonly initialDraws: number;
  drawsUsed: number;
};

type BoltTargetResult =
  | {
      readonly status: "target";
      readonly actor: CombatActor;

  statuses.some((entry) => entry.status === "blind" && entry.duration > 0) ? 1 : null;

const tickDamageOverTime: TickHook = ({ state }) => {
  const events: TurnEvent[] = [];
  let nextState = state;

  for (const entityId of statusEntityIdsInOrder(nextState)) {
    const result = applyDotForEntity(nextState, entityId);
    nextState = result.state;
    events.push(...result.events);
  }

  return { state: nextState, events };
};

const tickDurations: TickHook = ({ state }) => {
  const events: TurnEvent[] = [];
  let nextState = state;

  for (const entityId of statusEntityIdsInOrder(nextState)) {
    const result = decrementDurationsForEntity(nextState, entityId);
    nextState = result.state;
    events.push(...result.events);
  }

  return { state: nextState, events };
};

export const statusTickHooks = {
  damageOverTime: tickDamageOverTime,
  durations: tickDurations,
} as const satisfies Pick<TickHooks, StatusTickHookName>;

const tickHookSlots: Partial<Record<StatusTickHookName, TickHook>> = {};

const chainTickHooks = (
  existing: TickHook | undefined,
  next: TickHook,
): TickHook => {
  if (existing === undefined) {
    return next;
  }

  return (context) => {
    const first = normalizeTickHookResult(existing(context));
    const second = normalizeTickHookResult(
      next({
        ...context,
        state: first.state,
      }),
    );

    return {
      state: second.state,
      events: [...first.events, ...second.events],
    };
  };
};

export const registerStatusTickHooks = (): (() => void) => {
  const previous: Partial<Record<StatusTickHookName, TickHook | undefined>> = {
    damageOverTime: tickHookSlots.damageOverTime,
    durations: tickHookSlots.durations,
  };

  tickHookSlots.damageOverTime = chainTickHooks(
    previous.damageOverTime,
    tickDamageOverTime,
  );
  tickHookSlots.durations = chainTickHooks(previous.durations, tickDurations);

  return () => {
    if (previous.damageOverTime === undefined) {
      delete tickHookSlots.damageOverTime;
    } else {
      tickHookSlots.damageOverTime = previous.damageOverTime;
    }

    if (previous.durations === undefined) {
      delete tickHookSlots.durations;
    } else {
      tickHookSlots.durations = previous.durations;
    }
  };
};

export const getRegisteredStatusTickHooks = (): Pick<
  TickHooks,
  StatusTickHookName
> => ({
  damageOverTime: tickHookSlots.damageOverTime ?? (({ state }) => state),
  durations: tickHookSlots.durations ?? (({ state }) => state),
});

export const unregisterStatusTickHooks = registerStatusTickHooks();

const applyDotForEntity = (
  state: GameState,
  entityId: StatusEntityId,
): ApplyStatusResult => {
  const statuses = statusesForEntity(state, entityId);
  const dotStatuses = statuses.filter((entry) => DOT_STATUSES.has(entry.status));

  if (dotStatuses.length === 0) {
    return { state, events: [] };
  }

  const events: TurnEvent[] = [];
  let nextState = state;

  for (const entry of dotStatuses) {
    const hp = currentHp(nextState, entityId);
    if (hp === null) {
      continue;
    }

    let nextHp = hp.current;
    let hpDelta = 0;

    switch (entry.status) {
      case "poison":
        nextHp = Math.max(1, hp.current - 1);
        hpDelta = nextHp - hp.current;
        break;
      case "burn":
        nextHp = hp.current - 2;
        hpDelta = nextHp - hp.current;
        break;
      case "regen":
        nextHp = Math.min(hp.max, hp.current + 2);
        hpDelta = nextHp - hp.current;
        break;
      default:
        continue;
    }

    if (hpDelta !== 0) {
      events.push(
        statusEvent(state, "status_tick", {
          entityId,
          status: entry.status,
          hpDelta,
        }),
      );
    }

    if (entry.status === "burn" && nextHp <= 0) {
      const death = applyBurnDeath(nextState, entityId);
      return {
        state: death.state,
        events: [...events, ...death.events],
      };
    }

    nextState = setEntityHp(nextState, entityId, nextHp);
  }

  return { state: nextState, events };
};

const decrementDurationsForEntity = (
  state: GameState,
  entityId: StatusEntityId,
): ApplyStatusResult => {
  const statuses = statusesForEntity(state, entityId);
  if (statuses.length === 0) {
    return { state, events: [] };
  }

  const events: TurnEvent[] = [];
  const remaining: StatusApplication[] = [];

  for (const entry of statuses) {
    const nextDuration = entry.duration - 1;
    if (nextDuration <= 0) {
      events.push(
        statusEvent(state, "status_expired", {
          entityId,
          status: entry.status,
        }),
      );
      continue;
    }

    remaining.push({
      status: entry.status,
      duration: nextDuration,
    });
  }

  return {
    state: withEntityStatuses(state, entityId, remaining),
    events,
  };
};

const statusEntityIdsInOrder = (state: GameState): readonly StatusEntityId[] => [
  "player",
  ...Object.keys(state.entities)
    .sort((a, b) => a.localeCompare(b))
    .map((id) => id as EntityId),
];

const statusesForEntity = (
  state: GameState,
  entityId: StatusEntityId,
): readonly StatusApplication[] => {
  if (entityId === "player") {
    return state.player.statuses;
  }

  return state.entities[entityId]?.statuses ?? [];
};

const withEntityStatuses = (
  state: GameState,
  entityId: StatusEntityId,
  statuses: readonly StatusApplication[],
): GameState => {
  if (entityId === "player") {
    return {
      ...state,
      player: {
        ...state.player,
        statuses,
      },
    };
  }

  const entity = state.entities[entityId];
  if (entity === undefined) {
    return state;
  }

  return {
    ...state,
    entities: {
      ...state.entities,
      [entityId]: {
        ...entity,
        statuses,
      },
    },
  };
};

const currentHp = (
  state: GameState,
  entityId: StatusEntityId,
): { readonly current: number; readonly max: number } | null => {
  if (entityId === "player") {
    return state.player.hp;
  }

  const entity = state.entities[entityId];
  if (entity === undefined || entity.currentHP === null) {
    return null;
  }

  if (entity.kind === "enemy") {
    return {

      readonly actor: CombatActor;
    }
  | {
      readonly status: "miss";
      readonly reason: Exclude<AttackMissReason, "hit_roll">;
    };

export const deriveCombatStats = (
  state: GameState,
  actorId: CombatActorId,
): CombatStats | null => {
  const actor = combatActor(state, actorId);

  if (actor === null) {
    return null;
  }

  const stats =
    actor.kind === "player"
      ? playerBaseStats(state)
      : {
          attack: actor.entity.definition.stats.attack,
          defense: actor.entity.definition.stats.defense,
        };

  const withStatusModifiers = applyStatusModifiers(stats, actor.statuses);

  return {
    attack: Math.max(
      config.combatMath.minimumDamage,
      withStatusModifiers.attack,
    ),
    defense: withStatusModifiers.defense,
  };
};

export const calculateBaseDamage = (
  attackerAttack: number,
  defenderDefense: number,
): number =>
  Math.max(
    config.combatMath.minimumDamage,
    attackerAttack - defenderDefense,
  );

export const calculateDamage = (
  attackerAttack: number,
  defenderDefense: number,
  varianceMultiplier: number,
): number =>
  Math.max(
    config.combatMath.minimumDamage,
    Math.round(
      calculateBaseDamage(attackerAttack, defenderDefense) *
        varianceMultiplier,
    ),
  );

export const resolveAttack = (
  state: GameState,
  attackerId: CombatActorId,
  defenderId: CombatActorId,
): ActionResolverResult => {
  const attacker = combatActor(state, attackerId);
  const defender = combatActor(state, defenderId);

  if (attacker === null) {
    return {
      illegal: true,
      reason: `attacker ${attackerId} is not a combat actor`,
    };
  }

  if (defender === null) {
    return {
      illegal: true,
      reason: `defender ${defenderId} is not a combat actor`,
    };
  }

  if (!isAdjacent(attacker.position, defender.position)) {
    return {
      illegal: true,
      reason: `defender ${defenderId} is not adjacent to attacker ${attackerId}`,
    };
  }

  return resolveAttackRoll(state, attacker, defender);
};

export type BoltAttackOptions = {
  readonly range?: number;
};

export const resolveBoltAttack = (
  state: GameState,
  attackerId: CombatActorId,
  targetCell: Position,
  options: BoltAttackOptions = {},
): ActionResolverResult => {
  const attacker = combatActor(state, attackerId);

  if (attacker === null) {
    return {
      illegal: true,
      reason: `attacker ${attackerId} is not a combat actor`,
    };
  }

  const grid = gridFromState(state);
  if (grid === null) {
    return {
      illegal: true,
      reason: "floor geometry is not loaded",
    };
  }

  if (!inBounds(grid, targetCell)) {
    return {
      illegal: true,
      reason: `bolt target cell (${targetCell.x}, ${targetCell.y}) is outside the map`,
    };
  }

  const range =
    options.range ?? bounds.effectVocabulary.targetingShapes.boltRangeTiles.max;
  const rangeBounds = bounds.effectVocabulary.targetingShapes.boltRangeTiles;

  if (
    !Number.isSafeInteger(range) ||
    range < rangeBounds.min ||
    range > rangeBounds.max
  ) {
    return {
      illegal: true,
      reason: `bolt range must be ${rangeBounds.min}-${rangeBounds.max}`,
    };
  }

  const target = findBoltTarget(state, grid, attacker, targetCell, range);

  if (target.status === "miss") {
    return {
      state,
      events: [
        combatEvent(state, "attack_missed", {
          actorId: attacker.id,
          defenderId: null,
          attackerAttack: null,
          defenderDefense: null,
          hitRoll: null,
          hitChancePercent: config.combatMath.hitChancePercent,
          reason: target.reason,
        }),
      ],
    };
  }

  return resolveAttackRoll(state, attacker, target.actor);
};

export const resolveAttackAction: ActionResolver<AttackAction> = (
  state,
  action,
): ActionResolverResult => resolveAttack(state, "player", action.targetId);

export const registerCombatActionResolver = (): (() => void) =>
  registerActionResolver("attack", resolveAttackAction);

export const unregisterCombatActionResolver = registerCombatActionResolver();

export const registerLootDropHook = (hook: LootDropHook): (() => void) => {
  const previous = lootDropHook;
  lootDropHook = hook;

  return () => {
    if (lootDropHook === hook) {
      lootDropHook = previous;
    }
  };
};

const resolveAttackRoll = (
  state: GameState,
  attacker: CombatActor,
  defender: CombatActor,
): ActionResolverResult => {
  const attackerStats = deriveCombatStats(state, attacker.id);
  const defenderStats = deriveCombatStats(state, defender.id);

  if (attackerStats === null || defenderStats === null) {
    return {
      illegal: true,
      reason: "combat stats could not be derived",
    };
  }

  const rngContext = combatRngContextFor(state);
  const hitRoll = rollInt(rngContext, HIT_ROLL_MIN, HIT_ROLL_MAX);

  if (hitRoll > config.combatMath.hitChancePercent) {
    return {
      state: withCombatRngCursor(state, rngContext),
      events: [
        combatEvent(state, "attack_missed", {
          actorId: attacker.id,
          defenderId: defender.id,
          attackerAttack: attackerStats.attack,
          defenderDefense: defenderStats.defense,
          hitRoll,
          hitChancePercent: config.combatMath.hitChancePercent,
          reason: "hit_roll",
        }),
      ],
    };
  }

  const varianceMultiplier = rollVarianceMultiplier(rngContext);
  const baseDamage = calculateBaseDamage(
    attackerStats.attack,
    defenderStats.defense,
  );
  const damage = Math.max(
    config.combatMath.minimumDamage,
    Math.round(baseDamage * varianceMultiplier),
  );
  const defenderHpAfter = Math.max(0, defender.hp - damage);
  const damagedState = withActorHp(
    withCombatRngCursor(state, rngContext),
    defender,
    defenderHpAfter,
  );
  const events: TurnEvent[] = [
    combatEvent(state, "attack_hit", {
      actorId: attacker.id,
      defenderId: defender.id,
      attackerAttack: attackerStats.attack,
      defenderDefense: defenderStats.defense,
      baseDamage,
      damage,
      hitRoll,
      hitChancePercent: config.combatMath.hitChancePercent,
      varianceMultiplier,
      defenderHpBefore: defender.hp,
      defenderHpAfter,
    }),
  ];

  if (defenderHpAfter > 0) {
    return {
      state: damagedState,
      events,
    };
  }

  const deathResult = applyDeath(damagedState, attacker, defender);

  return {
    state: deathResult.state,
    events: [...events, ...deathResult.events],
  };
};

