const combatActor = (
  state: GameState,
  actorId: CombatActorId,
): CombatActor | null => {
  if (actorId === "player") {
    return {
      id: "player",
      kind: "player",
      position: state.player.position,
      hp: state.player.hp.current,
      statuses: state.player.statuses,
    };
  }

  const entity = state.entities[actorId];

  if (entity?.kind !== "enemy") {
    return null;
  }

  return {
    id: entity.id,
    kind: "enemy",
    entity,
    position: entity.position,
    hp: entity.currentHP,
