const setEntityHp = (
  state: GameState,
  entityId: StatusEntityId,
  current: number,
): GameState => {
  if (entityId === "player") {
    return {
      ...state,
      player: {
        ...state.player,
        hp: {
          ...state.player.hp,
          current,
        },
      },
    };
