const applyBurnDeath = (
  state: GameState,
  entityId: StatusEntityId,
): ApplyStatusResult => {
  if (entityId === "player") {
    return {
      state: setEntityHp(state, entityId, 0),
      events: [
        deathEvent(state, {
          entityId: "player",
          kind: "player",
          position: state.player.position,
          xpYield: 0,
        }),
      ],
    };
  }

  const entity = state.entities[entityId];
  if (entity === undefined || entity.kind !== "enemy") {
    return { state, events: [] };
  }

  const remainingEntities = { ...state.entities };
  delete remainingEntities[entityId];

  return {
    state: {
      ...state,
      entities: remainingEntities,
    },
    events: [
      deathEvent(state, {
        entityId,
        kind: "enemy",
        position: entity.position,
        xpYield: entity.definition.stats.xpYield,
      }),
    ],
  };
};

